import * as fs from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { afterEach, describe, expect, it } from 'vitest';
import {
  createDefaultCodeGraphyRepoMeta,
  getCodeGraphyRepoMetaPath,
  readCodeGraphyRepoMeta,
  writeCodeGraphyRepoMeta,
} from '../../../src/extension/repoSettings/meta';

function createTempWorkspace(): string {
  return fs.mkdtempSync(path.join(os.tmpdir(), 'codegraphy-repo-meta-'));
}

describe('extension/repoSettings/meta', () => {
  const tempDirectories: string[] = [];

  afterEach(() => {
    for (const directory of tempDirectories.splice(0)) {
      fs.rmSync(directory, { recursive: true, force: true });
    }
  });

  it('returns defaults when .codegraphy/meta.json is missing', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);

    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual(createDefaultCodeGraphyRepoMeta());
  });

  it('returns fresh default metadata values on each call', () => {
    const first = createDefaultCodeGraphyRepoMeta();
    const second = createDefaultCodeGraphyRepoMeta();

    expect(second).toEqual(first);
    expect(second).not.toBe(first);
    expect(second.pendingChangedFiles).not.toBe(first.pendingChangedFiles);
  });

  it('builds the meta path inside the repo-local .codegraphy directory', () => {
    expect(getCodeGraphyRepoMetaPath('/workspace/project')).toBe(
      path.join('/workspace/project', '.codegraphy', 'meta.json'),
    );
  });

  it('always uses meta.json as the persisted metadata filename', () => {
    expect(path.basename(getCodeGraphyRepoMetaPath('/workspace/project'))).toBe('meta.json');
  });

  it('writes and reads .codegraphy/meta.json', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const meta = {
      version: 1 as const,
      lastIndexedAt: '2026-04-08T19:00:00.000Z',
      lastIndexedCommit: 'abc123',
      pluginSignature: 'codegraphy.markdown@1.0.0',
      settingsSignature: 'settings-sha',
      pendingChangedFiles: ['src/index.ts'],
    };

    writeCodeGraphyRepoMeta(workspaceRoot, meta);
    writeCodeGraphyRepoMeta(workspaceRoot, meta);

    expect(fs.existsSync(getCodeGraphyRepoMetaPath(workspaceRoot))).toBe(true);
    expect(fs.readFileSync(getCodeGraphyRepoMetaPath(workspaceRoot), 'utf8')).toBe(
      `${JSON.stringify(meta, null, 2)}\n`,
    );
    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual(meta);
  });

  it('merges partial persisted meta with the default fields', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const metaPath = getCodeGraphyRepoMetaPath(workspaceRoot);

    fs.mkdirSync(path.dirname(metaPath), { recursive: true });
    fs.writeFileSync(
      metaPath,
      JSON.stringify({
        lastIndexedCommit: 'abc123',
        pendingChangedFiles: ['src/app.ts'],
      }, null, 2),
      'utf8',
    );

    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual({
      version: 1,
      lastIndexedAt: null,
      lastIndexedCommit: 'abc123',
      pluginSignature: null,
      settingsSignature: null,
      pendingChangedFiles: ['src/app.ts'],
    });
  });

  it('fills in an empty pendingChangedFiles list when persisted metadata omits it', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const metaPath = getCodeGraphyRepoMetaPath(workspaceRoot);

    fs.mkdirSync(path.dirname(metaPath), { recursive: true });
    fs.writeFileSync(
      metaPath,
      JSON.stringify({
        lastIndexedCommit: 'abc123',
      }, null, 2),
      'utf8',
    );

    expect(readCodeGraphyRepoMeta(workspaceRoot).pendingChangedFiles).toEqual([]);
  });

  it('falls back to defaults when meta.json is invalid', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const metaPath = getCodeGraphyRepoMetaPath(workspaceRoot);

    fs.mkdirSync(path.dirname(metaPath), { recursive: true });
    fs.writeFileSync(metaPath, '{bad json', 'utf8');

    expect(readCodeGraphyRepoMeta(workspaceRoot)).toEqual(createDefaultCodeGraphyRepoMeta());
  });

  it('skips writes when the workspace root does not exist', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    fs.rmSync(workspaceRoot, { recursive: true, force: true });
    const meta = {
      version: 1 as const,
      lastIndexedAt: '2026-04-08T19:00:00.000Z',
      lastIndexedCommit: 'abc123',
      pluginSignature: 'codegraphy.markdown@1.0.0',
      settingsSignature: 'settings-sha',
      pendingChangedFiles: ['src/index.ts'],
    };

    expect(fs.existsSync(workspaceRoot)).toBe(false);
    writeCodeGraphyRepoMeta(workspaceRoot, meta);

    expect(fs.existsSync(getCodeGraphyRepoMetaPath(workspaceRoot))).toBe(false);
  });
});

import * as fs from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { afterEach, describe, expect, it } from 'vitest';
import { createDefaultCodeGraphyRepoSettings } from '../../../src/extension/repoSettings/defaults';
import {
  CodeGraphyRepoSettingsStore,
  type ICodeGraphySettingsChangeEvent,
} from '../../../src/extension/repoSettings/store';

function createTempWorkspace(): string {
  return fs.mkdtempSync(path.join(os.tmpdir(), 'codegraphy-settings-'));
}

function readJson<T>(filePath: string): T {
  return JSON.parse(fs.readFileSync(filePath, 'utf8')) as T;
}

function createSettingsWithOverrides(overrides: Partial<ReturnType<typeof createDefaultCodeGraphyRepoSettings>>) {
  return {
    ...createDefaultCodeGraphyRepoSettings(),
    ...overrides,
  };
}

describe('extension/repoSettings/store', () => {
  const tempDirectories: string[] = [];

  afterEach(() => {
    for (const directory of tempDirectories.splice(0)) {
      fs.rmSync(directory, { recursive: true, force: true });
    }
  });

  it('creates .codegraphy/settings.json from defaults instead of seeding legacy configuration', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);

    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);

    const settingsPath = path.join(workspaceRoot, '.codegraphy', 'settings.json');
    const persisted = readJson<Record<string, unknown>>(settingsPath);

    expect(store.get('showOrphans', true)).toBe(true);
    expect(store.get('timeline.maxCommits', 0)).toBe(500);
    expect(persisted.showOrphans).toBe(true);
    expect(persisted.timeline).toEqual({ maxCommits: 500, playbackSpeed: 1 });
    expect(persisted.legend).toEqual([]);
  });

  it('creates .gitignore when missing and adds .codegraphy/ once', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);

    new CodeGraphyRepoSettingsStore(workspaceRoot);
    new CodeGraphyRepoSettingsStore(workspaceRoot);

    const gitIgnorePath = path.join(workspaceRoot, '.gitignore');
    expect(fs.readFileSync(gitIgnorePath, 'utf8')).toBe('.codegraphy/\n');
  });

  it('updates nested settings keys and persists the result', async () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);

    await store.update('timeline.playbackSpeed', 2.5);
    await store.update('physics.chargeRange', 450);

    const persisted = readJson<Record<string, unknown>>(store.settingsPath);
    expect(store.get('timeline.playbackSpeed', 0)).toBe(2.5);
    expect(store.get('physics.chargeRange', 0)).toBe(450);
    expect(persisted.timeline).toEqual({ maxCommits: 500, playbackSpeed: 2.5 });
    expect(persisted.physics).toEqual({
      repelForce: 10,
      linkDistance: 80,
      linkForce: 0.15,
      damping: 0.7,
      centerForce: 0.1,
      chargeRange: 450,
    });
  });

  it('persists silent updates without emitting a change event', async () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const changes: string[][] = [];
    store.onDidChange(event => {
      changes.push(event.changedKeys);
    });

    await store.updateSilently('disabledPlugins', ['codegraphy.python']);

    const persisted = readJson<Record<string, unknown>>(store.settingsPath);
    expect(store.get('disabledPlugins', [])).toEqual(['codegraphy.python']);
    expect(persisted.disabledPlugins).toEqual(['codegraphy.python']);
    expect(changes).toEqual([]);
  });

  it('reloads manual file edits and emits a change event', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const changes: string[][] = [];
    store.onDidChange(event => {
      changes.push(event.changedKeys);
    });

    fs.writeFileSync(
      store.settingsPath,
      JSON.stringify(createSettingsWithOverrides({ maxFiles: 900 }), null, 2),
      'utf8',
    );

    store.reload();

    expect(store.get('maxFiles', 0)).toBe(900);
    expect(changes).toEqual([['maxFiles']]);
  });

  it('emits nested keys for manual edits to nested settings', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const changes: string[][] = [];
    store.onDidChange(event => {
      changes.push(event.changedKeys);
    });

    fs.writeFileSync(
      store.settingsPath,
      JSON.stringify(createSettingsWithOverrides({
        timeline: { maxCommits: 500, playbackSpeed: 2 },
      }), null, 2),
      'utf8',
    );

    store.reload();

    expect(store.get('timeline.playbackSpeed', 0)).toBe(2);
    expect(changes).toEqual([['timeline.playbackSpeed']]);
  });

  it('reads persisted legend and node colors without legacy key aliases', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const settingsPath = path.join(workspaceRoot, '.codegraphy', 'settings.json');
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(
      settingsPath,
      JSON.stringify({
        ...createSettingsWithOverrides({}),
        legend: [{ id: 'legend-rule', pattern: 'src/**', color: '#112233' }],
        nodeColors: { file: '#999999', folder: '#445566' },
      }, null, 2),
      'utf8',
    );

    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);

    expect(store.get('legend', [])).toEqual([
      { id: 'legend-rule', pattern: 'src/**', color: '#112233' },
    ]);
    expect(store.get('nodeColors', {})).toEqual(expect.objectContaining({
      file: '#999999',
      folder: '#445566',
    }));
  });

  it('updates legend and persists only the legend key', async () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const nextLegend = [{ id: 'legend-rule', pattern: 'tests/**', color: '#00ff00' }];

    await store.update('legend', nextLegend);

    const persisted = readJson<Record<string, unknown>>(store.settingsPath);
    expect(store.get('legend', [])).toEqual(nextLegend);
    expect(persisted.legend).toEqual(nextLegend);
  });

  it('ignores legacy exclude entries in persisted settings files', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const settingsPath = path.join(workspaceRoot, '.codegraphy', 'settings.json');
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(
      settingsPath,
      JSON.stringify({
        ...createSettingsWithOverrides({}),
        filterPatterns: ['**/*.png'],
        exclude: ['**/*.tmp', '**/*.png'],
      }, null, 2),
      'utf8',
    );

    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);

    expect(store.get('filterPatterns', [])).toEqual(['**/*.png']);
  });

  it('ignores invalid manual saves and keeps the last valid settings in memory', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const changes: string[][] = [];
    store.onDidChange(event => {
      changes.push(event.changedKeys);
    });

    fs.writeFileSync(
      store.settingsPath,
      JSON.stringify(createSettingsWithOverrides({ maxFiles: 900 }), null, 2),
      'utf8',
    );
    store.reload();

    fs.writeFileSync(store.settingsPath, '{"maxFiles": }', 'utf8');
    expect(() => store.reload()).not.toThrow();

    expect(store.get('maxFiles', 0)).toBe(900);
    expect(changes).toEqual([['maxFiles']]);
  });

  it('prefers existing legend and node color entries over legacy aliases while cleaning excludes', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const settingsPath = path.join(workspaceRoot, '.codegraphy', 'settings.json');
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(
      settingsPath,
      JSON.stringify({
        ...createSettingsWithOverrides({}),
        legend: [{ id: 'legend-rule', pattern: 'src/**', color: '#112233' }],
        groups: [{ id: 'legacy-group', pattern: 'legacy/**', color: '#ffffff' }],
        nodeColors: { folder: '#445566', file: '#999999' },
        folderNodeColor: '#000000',
        filterPatterns: ['**/*.png'],
        exclude: ['**/*.png', 42],
      }, null, 2),
      'utf8',
    );

    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const persisted = readJson<Record<string, unknown>>(store.settingsPath);

    expect(store.get('legend', [])).toEqual([
      { id: 'legend-rule', pattern: 'src/**', color: '#112233' },
    ]);
    expect(store.get('folderNodeColor', '')).toBe('#445566');
    expect(persisted.legend).toEqual([
      { id: 'legend-rule', pattern: 'src/**', color: '#112233' },
    ]);
    expect(persisted.nodeColors).toEqual(expect.objectContaining({
      folder: '#445566',
      file: '#999999',
    }));
    expect(persisted.exclude).toBeUndefined();
    expect(persisted.filterPatterns).toEqual(['**/*.png']);
  });

  it('falls back to defaults when persisted settings are a non-object JSON value', () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const settingsPath = path.join(workspaceRoot, '.codegraphy', 'settings.json');
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, '[]\n', 'utf8');

    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);

    expect(store.get('legend', [])).toEqual([]);
    expect(store.get('filterPatterns', [])).toEqual([]);
    expect(readJson<Record<string, unknown>>(store.settingsPath)).toEqual(
      createDefaultCodeGraphyRepoSettings(),
    );
  });

  it('reports alias and parent-child matches through affectsConfiguration', async () => {
    const workspaceRoot = createTempWorkspace();
    tempDirectories.push(workspaceRoot);
    const store = new CodeGraphyRepoSettingsStore(workspaceRoot);
    const events: ICodeGraphySettingsChangeEvent[] = [];

    store.onDidChange((event) => {
      events.push(event);
    });

    await store.update('legend', [{ id: 'legend-rule', pattern: 'src/**', color: '#abcdef' }]);
    await store.update('timeline.playbackSpeed', 3);
    await store.update('nodeColors', { folder: '#123456' });

    expect(events[0].affectsConfiguration('codegraphy')).toBe(true);
    expect(events[0].affectsConfiguration('codegraphy.groups')).toBe(true);
    expect(events[0].affectsConfiguration('workbench.colorTheme')).toBe(false);

    expect(events[1].affectsConfiguration('codegraphy.timeline')).toBe(true);
    expect(events[1].affectsConfiguration('codegraphy.timeline.playbackSpeed')).toBe(true);

    expect(events[2].affectsConfiguration('codegraphy.folderNodeColor')).toBe(true);
    expect(events[2].affectsConfiguration('codegraphy.nodeColors')).toBe(true);
  });
});

import * as fs from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { afterEach, describe, expect, it, vi } from 'vitest';
import { createDefaultCodeGraphyRepoSettings } from '../../../src/extension/repoSettings/defaults';
import {
  createUpdatedSettings,
  readSettingsFromDisk,
  reloadSettingsFromDisk,
  writeSettingsToDisk,
} from '../../../src/extension/repoSettings/storeState';
import { serializeSettings } from '../../../src/extension/repoSettings/storeSerialization';

vi.mock('node:fs', async () => {
  const actual = await vi.importActual<typeof import('node:fs')>('node:fs');
  return {
    ...actual,
    readFileSync: vi.fn(actual.readFileSync),
    writeFileSync: vi.fn(actual.writeFileSync),
  };
});

function createTempSettingsPath(): string {
  const workspaceRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'codegraphy-store-state-'));
  return path.join(workspaceRoot, '.codegraphy', 'settings.json');
}

describe('extension/repoSettings/storeState', () => {
  const tempDirectories: string[] = [];

  afterEach(() => {
    vi.restoreAllMocks();
    for (const directory of tempDirectories.splice(0)) {
      fs.rmSync(directory, { recursive: true, force: true });
    }
  });

  it('creates updated settings without mutating the previous state', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settings = createDefaultCodeGraphyRepoSettings();

    const updated = createUpdatedSettings(defaults, settings, 'timeline.playbackSpeed', 2.5);

    expect(updated.timeline.playbackSpeed).toBe(2.5);
    expect(updated.timeline.maxCommits).toBe(500);
    expect(settings.timeline.playbackSpeed).toBe(1);
  });

  it('reads, normalizes, merges, and rewrites persisted settings when the shape changed', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, JSON.stringify({
      maxFiles: 250,
      filterPatterns: ['**/*.png', '**/*.png'],
      exclude: ['legacy'],
      groups: [{ id: 'group-1', pattern: 'src/**', color: '#123456' }],
      folderNodeColor: '#445566',
    }, null, 2), 'utf8');

    const state = readSettingsFromDisk(settingsPath, defaults);

    expect(state.settings.maxFiles).toBe(250);
    expect(state.settings.filterPatterns).toEqual(['**/*.png']);
    expect(state.settings.legend).toEqual([{ id: 'group-1', pattern: 'src/**', color: '#123456' }]);
    expect(state.settings.nodeColors.folder).toBe('#445566');
    expect(state.serializedSettings).toBe(fs.readFileSync(settingsPath, 'utf8'));
    expect(fs.readFileSync(settingsPath, 'utf8')).toContain('"legend"');
    expect(fs.readFileSync(settingsPath, 'utf8')).not.toContain('"exclude"');
    expect(fs.readFileSync(settingsPath, 'utf8')).not.toContain('"folderNodeColor"');
  });

  it('reads an already-normalized settings file without rewriting it', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    const serializedDefaults = serializeSettings(defaults);
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, serializedDefaults, 'utf8');
    const readFileSyncMock = vi.mocked(fs.readFileSync);
    const writeFileSyncMock = vi.mocked(fs.writeFileSync);
    readFileSyncMock.mockClear();
    writeFileSyncMock.mockClear();

    const state = readSettingsFromDisk(settingsPath, defaults);

    expect(state).toEqual({
      serializedSettings: serializedDefaults,
      settings: defaults,
    });
    expect(readFileSyncMock).toHaveBeenCalledWith(settingsPath, 'utf8');
    expect(writeFileSyncMock).not.toHaveBeenCalled();
  });

  it('regenerates defaults when reading invalid settings files', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, '{"maxFiles": }', 'utf8');
    const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => undefined);
    const writeFileSyncMock = vi.mocked(fs.writeFileSync);
    writeFileSyncMock.mockClear();

    const state = readSettingsFromDisk(settingsPath, defaults);

    expect(warnSpy).toHaveBeenCalledExactlyOnceWith(
      '[CodeGraphy] Failed to read .codegraphy/settings.json, regenerating defaults.',
      expect.any(SyntaxError),
    );
    expect(state.settings).toEqual(defaults);
    expect(state.serializedSettings).toBe(serializeSettings(defaults));
    expect(fs.readFileSync(settingsPath, 'utf8')).toBe(serializeSettings(defaults));
    expect(writeFileSyncMock).toHaveBeenCalledWith(settingsPath, serializeSettings(defaults), 'utf8');
  });

  it('writes settings and returns the serialized form', () => {
    const settings = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    const writeFileSyncMock = vi.mocked(fs.writeFileSync);
    writeFileSyncMock.mockClear();

    const serialized = writeSettingsToDisk(settingsPath, settings);

    expect(serialized).toBe(serializeSettings(settings));
    expect(fs.readFileSync(settingsPath, 'utf8')).toBe(serialized);
    expect(writeFileSyncMock).toHaveBeenCalledWith(settingsPath, serialized, 'utf8');
  });

  it('reloads defaults when the persisted file disappears', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const previousSettings = { ...defaults, showOrphans: false };
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });

    const nextState = reloadSettingsFromDisk(
      settingsPath,
      defaults,
      previousSettings,
      serializeSettings(previousSettings),
    );

    expect(nextState).toEqual({
      changedKeys: ['showOrphans'],
      serializedSettings: serializeSettings(defaults),
      settings: defaults,
    });
    expect(fs.readFileSync(settingsPath, 'utf8')).toBe(serializeSettings(defaults));
  });

  it('reloads defaults with a fallback change key when the missing file matches prior settings', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });

    const nextState = reloadSettingsFromDisk(
      settingsPath,
      defaults,
      defaults,
      serializeSettings(defaults),
    );

    expect(nextState).toEqual({
      changedKeys: ['codegraphy'],
      serializedSettings: serializeSettings(defaults),
      settings: defaults,
    });
  });

  it('returns undefined when a reload sees the same serialized settings', () => {
    const settings = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, serializeSettings(settings), 'utf8');

    expect(reloadSettingsFromDisk(
      settingsPath,
      settings,
      settings,
      serializeSettings(settings),
    )).toBeUndefined();
  });

  it('returns normalized settings and a fallback change key when only formatting changed', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, `${JSON.stringify(defaults)}\n`, 'utf8');

    const nextState = reloadSettingsFromDisk(
      settingsPath,
      defaults,
      defaults,
      'stale-serialized-value',
    );

    expect(nextState).toEqual({
      changedKeys: ['codegraphy'],
      serializedSettings: serializeSettings(defaults),
      settings: defaults,
    });
  });

  it('ignores invalid reload saves and preserves the in-memory state', () => {
    const defaults = createDefaultCodeGraphyRepoSettings();
    const settingsPath = createTempSettingsPath();
    tempDirectories.push(path.dirname(path.dirname(settingsPath)));
    fs.mkdirSync(path.dirname(settingsPath), { recursive: true });
    fs.writeFileSync(settingsPath, '{"showOrphans": }', 'utf8');
